  status: DocumentStatus;
};

export type UpdateAccountDocument = {
  accountId: string;
  documentName: string;
  documentType: AccountDocumentType;
  file: string;
};

/*

  The word "category" is overloaded here. Each account category has a many document categories that it needs to fulfill.
    Each document categtory has one or more documents that would fulfill that category. So, for a account category we will
    show each document category that they need to fulfill.
*/
// export const DOCUMENTS_BY_CATEGORY: Record<AccountCategory, readonly DocumentType[]> = {
