import { Box, Link as ChakraLink, Flex } from '@chakra-ui/react';
import {
  AccountDocument,
  AccountDocumentCategories,
  type AccountDocumentType,
  DocumentCategory,
  getRequiredDocumentCategories,
} from '@domain/accountDocument';
import { ApiClient } from '@service/anedot/client';
import { useGetAccountDocuments } from '@state/accountDocuments';
import { useGetAccount } from '@state/accounts';
import { Form } from '@ui/components/formControls/Form';
import { Loading } from '@ui/components/Loading';
import { Panel } from '@ui/components/Panel';
import { Heading, Paragraph } from '@ui/components/typography';
import { snakeToCamel } from '@utils/snakeToCamel';
import { useEffect, useState } from 'react';
import { Trans, useTranslation } from 'react-i18next';
import { Link as RouterLink } from 'react-router-dom';
import { StepFooter } from '../StepFooter';
import { useSteps } from '../useSteps';
import { DocumentationUploader } from './DocumentationUploader';
import { getSchema } from './schema';

const getFileByType = (
  accountDocuments: AccountDocument[] | undefined,
  documentTypeParam: string
) => accountDocuments?.find(({ documentType }) => documentType === documentTypeParam);

const getFileByCategory = (
  accountDocuments: AccountDocument[] | undefined,
  categoryDocuments: AccountDocumentType[]
) => {
  return accountDocuments?.find(({ documentType }) => categoryDocuments.includes(documentType));
};

export const getRequiredAccountDocuments = async ({ accountId }: { accountId: string }) => {
  return new ApiClient()
    .get<AccountDocumentCategories>(`/accounts/${accountId}/draft_requirements`)
    .then(() => ({}))
    .catch(() => ({
      // here is where the actual results we're looking for are
      //  but currently they are just a set of error messages
    }));
};

export function Documentation() {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'documentation' });
  const { navigateNextStep } = useSteps();

  const { currentAccount, isLoading } = useGetAccount();
  const { accountDocuments, accountDocumentsIsLoading } = useGetAccountDocuments();
  const [requiredDocumentCategories, setRequiredDocumentCategories] = useState<
    AccountDocumentCategories | {}
  >({});

  useEffect(() => {
    if (!currentAccount?.id) {
      return;
    }

    setRequiredDocumentCategories(
      getRequiredDocumentCategories({
        accountCategory: currentAccount.category,
        subCategory: currentAccount.subCategory,
        state: currentAccount.state,
      })
    );
    // getRequiredAccountDocuments({ accountId: currentAccount.id }).then((result) =>
    //   setRequiredDocumentCategories(result)
    // );
  }, []);

  if (isLoading || accountDocumentsIsLoading) {
    return <Loading />;
  }

  if (!currentAccount?.category) {
    return (
      <Box>
        <Trans
          components={{ hlink: <ChakraLink as={RouterLink} to=".." /> }}
          i18nKey="categoryCheck"
          t={t}
        />
      </Box>
    );
  }

  return (
    <>
      <hgroup>
        <Heading as="h1">{t('heading')}</Heading>
        <Paragraph as="h2">{currentAccount?.displayName}</Paragraph>
      </hgroup>
      <Form onSubmit={() => navigateNextStep()}>
        <Flex direction="column" gap={6}>
          <Panel p={6} variant="primary">
            <Flex direction="column" gap={6}>
              <Box>
                <Paragraph as="h3">{t('subheading')}</Paragraph>
                <Paragraph>{t('intro')}</Paragraph>
              </Box>
              {Object.entries(requiredDocumentCategories).map(
                ([documentCategory, categoryDocuments]) => {
                  const i18nKey = snakeToCamel(documentCategory);
                  // const isRequired = ['irs_w9', 'irs_cp_575'].includes(documentCategory);
                  const docCategory = documentCategory as DocumentCategory;

                  return (
                    <DocumentationUploader
                      currentFile={getFileByCategory(accountDocuments, categoryDocuments)}
                      description={t(
                        `categories.${i18nKey}.description` as Parameters<typeof t>[0]
                      )}
                      documentCategory={docCategory}
                      categoryDocuments={categoryDocuments}
                      isRequired={true}
                      key={documentCategory}
                      label={t(`categories.${i18nKey}.heading` as Parameters<typeof t>[0])}
                    />
                  );
                }
              )}
              <Paragraph>{t('footer')}</Paragraph>
            </Flex>
          </Panel>
          <StepFooter />
        </Flex>
      </Form>
    </>
  );
}

