import { useCallback, useEffect, useRef, useState } from 'react';
import { useMutation } from 'react-query';

export type FileUploader = {
  (
    file: File,
    signal: AbortSignal,
    onUploadProgress: (progressEvent: ProgressEvent) => void
  ): Promise<{ id: string }>;
};

export type FileDeleter = {
  (id: string): Promise<unknown>;
};

type UploadStatus = 'pending' | 'complete' | 'error';

export type FileUpload = {
  abortController?: AbortController;
  file: File;
  id?: string;
  progressPercentage: number;
  status: UploadStatus;
};

type UseFileUploaderParams = {
  deleter: FileDeleter;
  initialUploads?: FileUpload[];
  uploader: FileUploader;
};

export const useFileUploader = ({
  deleter,
  initialUploads = [],
  uploader,
}: UseFileUploaderParams) => {
  const [uploads, setUploads] = useState<FileUpload[]>(initialUploads);

  const setUpload = useCallback((changedUpload: Require<FileUpload, 'file'>) => {
    setUploads((u) =>
      u.map((upload) =>
        upload.file === changedUpload.file ? { ...upload, ...changedUpload } : upload
      )
    );
  }, []);

  const uploadFile = useCallback(
    async (file: File) => {
      const abortController = new AbortController();
      setUploads((u) => [
        ...u,
        {
          abortController,
          file,
          progressPercentage: 0,
          status: 'pending',
        },
      ]);

      return uploader(file, abortController?.signal, (progressEvent) => {
        const progress = Math.round((progressEvent.loaded * 100) / progressEvent.total);
        setUpload({ file, progressPercentage: progress });
      });
    },
    [uploader, setUpload]
  );

  const { mutate: addFile } = useMutation(uploadFile, {
    onError(_, file) {
      setUpload({ file, status: 'error' });
    },
    onSuccess(response, file) {
      setUpload({ file, id: response.id, status: 'complete' });
    },
  });

  const { mutate: removeFile } = useMutation(async (file: File) => {
    const upload = uploads.find((u) => u.file === file);

    upload?.abortController?.abort();

    if (upload?.status === 'complete' && !!upload.id) {
      await deleter(upload.id);
    }

    setUploads((currentUploads) => currentUploads.filter((u) => u !== upload));
  });

  const haveCompletedAllUploads = !!uploads.length && uploads.every((u) => u.status === 'complete');

  // Aborts any active uploads when component is closed
  const uploadRef = useRef(uploads);
  useEffect(() => {
    uploadRef.current = uploads;
  }, [uploads]);

  useEffect(() => {
    return () => {
      uploadRef.current?.forEach((u) => u.abortController?.abort());
    };
  }, []);

  return {
    addFile,
    haveCompletedAllUploads,
    removeFile,
    uploads,
  };
};

