import { Box, Flex, Select, Text } from '@chakra-ui/react';
import { AccountDocument, AccountDocumentType, DocumentCategory } from '@domain/accountDocument';
import { FileUpload } from '@state/utils';
import { UploadIcon } from '@ui/assets/icons/UploadIcon';
import { FormControl } from '@ui/components/formControls/FormControl';
import { useControl } from '@ui/components/formControls/hooks';
import { FileUploader } from '@ui/components/molecules/FileUploader';
import { Upload } from '@ui/components/molecules/FileUploader/types';
import { Label, Meta } from '@ui/components/typography';
import { snakeToCamel } from '@utils/snakeToCamel';
import { useEffect, useMemo, useState } from 'react';
import { Trans, useTranslation } from 'react-i18next';
import { useDocumentationUploader } from './useDocumentationUploader';

type Props = {
  currentFile?: AccountDocument;
  description: string;
  documentCategory: DocumentCategory;
  categoryDocuments: AccountDocumentType[];
  isRequired?: boolean;
  label: string;
};

export const DocumentationUploader = ({
  currentFile,
  description,
  documentCategory,
  categoryDocuments,
  isRequired,
  label,
}: Props) => {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'documentation.uploader' });
  const { t: tDocumentation } = useTranslation('organizationApplication', {
    keyPrefix: 'documentation',
  });
  const { error } = useControl({ name: documentCategory });
  const selectId = `${documentCategory}-document-type`;
  const selectLabelId = `${selectId}-label`;
  const initialUploads: FileUpload[] = currentFile
    ? [
        {
          file: new File([], currentFile.file.name),
          id: currentFile.id,
          progressPercentage: 100,
          status: 'complete',
        },
      ]
    : [];

  const fallbackDocumentType = categoryDocuments[0] ?? 'irs_w9';
  const defaultDocumentType = useMemo<AccountDocumentType>(
    () => currentFile?.documentType ?? fallbackDocumentType,
    [currentFile?.documentType, fallbackDocumentType]
  );
  const shouldShowSelector = categoryDocuments.length > 1;
  const [selectedDocumentType, setSelectedDocumentType] =
    useState<AccountDocumentType>(defaultDocumentType);

  useEffect(() => {
    if (defaultDocumentType) {
      setSelectedDocumentType(defaultDocumentType);
    }
  }, [defaultDocumentType]);

  const documentOptions = useMemo(
    () =>
      categoryDocuments.map((documentType) => ({
        label: tDocumentation(
          `${snakeToCamel(documentType)}.heading` as Parameters<typeof tDocumentation>[0]
        ),
        value: documentType,
      })),
    [categoryDocuments, tDocumentation]
  );

  const { addFile, removeFile, uploads } = useDocumentationUploader({
    documentCategory,
    documentType: selectedDocumentType,
    initialUploads,
  });

  const onAddFiles = (files: File[]) => {
    files.forEach((file) => addFile(file));
  };

  const uploadArr: Upload[] = uploads.map((upload) => ({
    file: upload.file,
    progress: upload.progressPercentage,
    status: upload.status,
  }));

  return (
    <FormControl formLabelProps={{ variant: 'bold' }} isRequired={isRequired} label={label}>
      <Flex direction="column" gap={2}>
        <Meta>{description}</Meta>
        {shouldShowSelector && (
          <Flex direction="column" gap={1}>
            <Select
              aria-labelledby={selectLabelId}
              id={selectId}
              onChange={(event) =>
                setSelectedDocumentType(event.target.value as AccountDocumentType)
              }
              value={selectedDocumentType}
              variant="outline"
            >
              {documentOptions.map(({ label, value }) => (
                <option key={value} value={value}>
                  {label}
                </option>
              ))}
            </Select>
          </Flex>
        )}
        <FileUploader
          acceptedFileTypes={['application/pdf', 'image/jpeg', 'image/png']}
          hasError={!!error}
          onAddFiles={onAddFiles}
          onRemoveFile={removeFile}
          previewPath={currentFile?.file.url}

